+struct StatementLookasideGrowthGuard<'a> {
+    conn: &'a Connection,
+    before_bytes: usize,
+}
+
+impl<'a> StatementLookasideGrowthGuard<'a> {
+    fn new(conn: &'a Connection) -> Self {
+        Self {
+            conn,
+            before_bytes: conn.statement_lookaside_retained_bytes(),
+        }
+    }
+}
+
+impl Drop for StatementLookasideGrowthGuard<'_> {
+    fn drop(&mut self) {
+        self.conn
+            .note_statement_lookaside_alloc_growth(self.before_bytes);
+    }
+}
