+    fn note_statement_lookaside_alloc_growth(&self, before_bytes: usize) {
+        if !hot_path_profile_enabled() {
+            return;
+        }
+        let after_bytes = self.statement_lookaside_retained_bytes();
+        let growth = after_bytes.saturating_sub(before_bytes);
+        if growth > 0 {
+            FSQLITE_ARENA_ALLOC_BYTES.fetch_add(
+                u64::try_from(growth).unwrap_or(u64::MAX),
+                AtomicOrdering::Relaxed,
+            );
+        }
+    }
